mapper.select:
select count(*)
from biz_backpacker_chat_message m
where m.order_id = #{orderId}
  and m.sender_id != #{userId}
  and m.message_id > coalesce(
        (select r.last_read_message_id
         from biz_backpacker_chat_read r
         where r.order_id = #{orderId}
           and r.user_id = #{userId}),
        0)
